import { Linking, Alert } from 'react-native';
import { useNavigation } from '@react-navigation/native';

const allowedHosts = ['myapp://'];

const handleDeepLink = (url) => {
  const parsedUrl = url.replace(/^https?:\/\//, '');
  const [host, path] = parsedUrl.split('/');

  if (!allowedHosts.includes(host)) return;

  switch (path) {
    case 'profile':
      const profileId = path.split('/')[1];
      if (!/^\d+$/.test(profileId)) return;
      navigation.navigate('Profile', { id: parseInt(profileId, 10) });
      break;
    case 'payment':
      const paymentAction = path.split('/')[1];
      if (paymentAction !== 'confirm') return;
      navigation.navigate('Payment');
      break;
    default:
      return;
  }
};

const App = () => {
  const navigation = useNavigation();

  Linking.addEventListener('url', ({ url }) => handleDeepLink(url));

  return (
    <View>
      {/* Your app content here */}
    </View>
  );
};